const response = JSON.parse($input.first().json.choices[0].message.content);
const evraklar = response.evraklar;
const applicationId = $('Webhook').first().json.body.application_id;

return evraklar.map(evrak => ({
  json: {
    application_id: applicationId,
    doc_name: evrak.doc_name,
    delivery_type: evrak.delivery_type,
    description: evrak.description,
    status: 'pending'
  }
}));
